import{_ as r,C as o,o as E,c as i,a2 as e,E as l}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"RAG 笔记：检索结果不是系统指令","description":"","frontmatter":{},"headers":[],"relativePath":"agent/rag-notes.md","filePath":"agent/rag-notes.md","lastUpdated":1782915681000}'),p={name:"agent/rag-notes.md"};function n(A,a,d,s,B,c){const t=o("Mermaid");return E(),i("div",null,[a[0]||(a[0]=e('<h1 id="rag-笔记-检索结果不是系统指令" tabindex="-1">RAG 笔记：检索结果不是系统指令 <a class="header-anchor" href="#rag-笔记-检索结果不是系统指令" aria-label="Permalink to &quot;RAG 笔记：检索结果不是系统指令&quot;">​</a></h1><p>RAG 很容易被做成“向量库 + top-k + Prompt 拼接”。这个版本能快速出效果，但风险也很明显：检索到的内容不一定正确，不一定相关，更不能当成系统指令。</p><p>我现在更愿意把 RAG 看成上下文治理，而不是检索功能。</p><h2 id="早期方案为什么不够" tabindex="-1">早期方案为什么不够 <a class="header-anchor" href="#早期方案为什么不够" aria-label="Permalink to &quot;早期方案为什么不够&quot;">​</a></h2><p>最早的思路很标准：</p><ol><li>文件抽文本。</li><li>切 chunk。</li><li>计算 embedding。</li><li>用户提问时向量检索。</li><li>把 top-k 结果塞进上下文。</li></ol><p>这个方案能跑，但真实使用会遇到几个问题。</p><p>语义相似不等于任务相关。embedding 找到的是“像”，不是“有用”。没有 rerank 和评测时，top-k 只能算候选资料。</p><p>外部资料不可信。用户文件、网页、工具输出都可能包含干扰指令。直接拼进 Prompt，模型可能把资料里的指令当成系统要求。</p><p>上下文窗口有限。检索结果、历史消息、工具说明、记忆、附件一起进上下文，很快会膨胀。</p><p>长期记忆更难。模型会总结，但它不一定知道什么值得长期保存。</p><h2 id="我现在的-rag-链路" tabindex="-1">我现在的 RAG 链路 <a class="header-anchor" href="#我现在的-rag-链路" aria-label="Permalink to &quot;我现在的 RAG 链路&quot;">​</a></h2>',12)),l(t,{code:"flowchart%20TD%0A%20%20%20%20Query%5B%22%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%22%5D%20--%3E%20Retrieve%5B%22%E6%A3%80%E7%B4%A2%3Cbr%2F%3E%E5%90%91%E9%87%8F%20%2F%20%E5%85%B3%E9%94%AE%E8%AF%8D%20%2F%20%E5%85%83%E6%95%B0%E6%8D%AE%22%5D%0A%20%20%20%20Retrieve%20--%3E%20Budget%5B%22Token%20%E9%A2%84%E7%AE%97%E8%A3%81%E5%89%AA%22%5D%0A%20%20%20%20Budget%20--%3E%20Wrap%5B%22%E4%B8%8D%E5%8F%AF%E4%BF%A1%E8%B5%84%E6%96%99%E5%8C%85%E8%A3%85%22%5D%0A%20%20%20%20Wrap%20--%3E%20Context%5B%22%E4%B8%8A%E4%B8%8B%E6%96%87%E7%BB%84%E8%A3%85%22%5D%0A%20%20%20%20Context%20--%3E%20Model%5B%22%E6%A8%A1%E5%9E%8B%E5%9B%9E%E7%AD%94%22%5D%0A%20%20%20%20Model%20--%3E%20MemoryCandidate%5B%22%E5%80%99%E9%80%89%E8%AE%B0%E5%BF%86%22%5D%0A%20%20%20%20MemoryCandidate%20--%3E%20Policy%7B%22%E7%AD%96%E7%95%A5%E8%BF%87%E6%BB%A4%20%2F%20%E7%94%A8%E6%88%B7%E7%A1%AE%E8%AE%A4%22%7D%0A%20%20%20%20Policy%20--%20%22%E9%80%9A%E8%BF%87%22%20--%3E%20Memory%5B%22%E9%95%BF%E6%9C%9F%E8%AE%B0%E5%BF%86%22%5D%0A%20%20%20%20Policy%20--%20%22%E6%8B%92%E7%BB%9D%22%20--%3E%20Drop%5B%22%E4%B8%A2%E5%BC%83%E6%88%96%E5%BE%85%E7%A1%AE%E8%AE%A4%22%5D%0A"}),a[1]||(a[1]=e('<p>检索只是第一步。更关键的是预算、包装和注入方式。</p><p>检索结果应该以外部资料身份进入上下文。它可以帮助回答，但不能改写系统规则，也不应该伪装成用户消息。</p><p>记忆也要走策略。显式记忆可信度更高，自动抽取的记忆需要过滤。指令型、策略型、工具型内容不应该被长期记住。</p><h2 id="需要承认的取舍" tabindex="-1">需要承认的取舍 <a class="header-anchor" href="#需要承认的取舍" aria-label="Permalink to &quot;需要承认的取舍&quot;">​</a></h2><p>朴素 RAG 的优点是简单，能快速打通链路。缺点是质量不稳定。</p><p>没有 rerank 时，召回片段可能相关但无用。只有关键词 fallback 时，同义表达又容易漏。chunk 策略简单时，文档语义可能被切断。</p><p>严格包装外部资料会让模型表达没那么自然，但这是必要的。资料可以被参考，不能获得系统级话语权。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是把文件内容直接当用户消息注入。这样会破坏对话边界，也容易引入 prompt injection。</p><p>第二个坑，是长期记忆越记越多。记忆越多不代表越聪明，很多时候只是噪声变多。</p><p>第三个坑，是没有检索评测。只靠肉眼感觉调 top-k 和 chunk size，后面很难判断是否真的变好。</p><p>第四个坑，是忽略权限和范围。项目资料、用户资料、全局记忆应该有清晰边界。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果重新做，我会更早加入 hybrid retrieval：向量、关键词、元数据一起工作。然后补简单评测集和 rerank。</p><p>记忆会从一开始设计生命周期：待确认、激活、过期、合并、删除、冲突检测。</p><p>一句话总结：RAG 的核心不是找到了什么，而是这些资料能不能、该不该、以什么身份进入上下文。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么 RAG 不是向量库功能。</li><li>top-k 拼 Prompt 的几个隐患。</li><li>检索结果为什么不能当系统指令。</li><li>长期记忆为什么比检索更危险。</li><li>Context Assembler 在安全上的作用。</li><li>Rerank 和评测为什么迟早要补。</li><li>如果重做，我会怎样设计记忆生命周期。</li></ol>',18))])}const m=r(p,[["render",n]]);export{_ as __pageData,m as default};
